const bin = $input.first().binary?.data;
const sizeKb = bin ? Math.round(Buffer.from(bin.data, 'base64').length / 1024) : 0;
const pass = sizeKb >= 40; // crude blur/quality proxy for V0: tiny files are unusable
return [{ json: { ...$('Profiler Trigger').first().json, size_kb: sizeKb, quality_pass: pass, image_b64: pass ? bin.data : null, mime: bin?.mimeType || 'image/jpeg' } }];

const ctx = $('Quality Gate').first().json;
let out = { doc_type: 'other', fields: {}, aadhaar_last4: null };
try {
  const raw = $json.candidates?.[0]?.content?.parts?.[0]?.text || '';
  out = JSON.parse(raw.replace(/```json|```/g, '').trim());
} catch (e) {}
const f = out.fields || {};
const profile = {};
if (f.name) profile.name = f.name;
if (f.gender) profile.gender = String(f.gender).toLowerCase();
if (f.district) profile.district = f.district;
if (f.state) profile.state = f.state;
if (f.category) profile.category = f.category;
if (f.marital_status) profile.marital_status = String(f.marital_status).toLowerCase();
if (f.annual_income) profile.annual_income = Number(f.annual_income);
if (f.dob_or_age) {
  const n = Number(f.dob_or_age);
  if (!isNaN(n) && n > 0 && n < 120) profile.age = n;
  else { const y = new Date(f.dob_or_age).getFullYear(); if (y > 1900) profile.age = new Date().getFullYear() - y; }
}
return [{ json: { chat_id: ctx.chat_id, doc_type: out.doc_type, doc_fields: f, aadhaar_last4: out.aadhaar_last4 || null, profile_patch: profile } }];

const j = $json;
const profile = j.profile || {};
const needed = (j.needed_fields || []).filter(Boolean);
const missing = needed.filter(f => profile[f] === undefined || profile[f] === null);
const qs = {
  age: 'Aapki umar kitni hai?',
  gender: 'Aap mahila hain ya purush?',
  marital_status: 'Aapki vaivahik sthiti kya hai? (vivahit / vidhva / avivahit)',
  annual_income: 'Aapke parivaar ki saalana aamdani lagbhag kitni hai?',
  category: 'Aapki shreni kya hai? (GEN / OBC / SC / ST)',
  district: 'Aap kis zile mein rehte hain?',
  state: 'Aap kis rajya mein rehte hain?'
};
const ask = missing.slice(0, 2).map(f => qs[f] || `Kripya bataiye: ${f}`);
return [{ json: { user_id: j.user_id, chat_id: $('Parse & Mask').first().json.chat_id, has_gaps: ask.length > 0, question: ask.join('\n') } }];
